    [dl('Asset coordinates, engineering specifications, hazard return-period maps, adaptation cost databases', 'Hazard linkage, residual risk modelling, NPV and ABCR calculation', 'Adaptation option rankings, ABCR heat maps, resilience certification inputs')],
