    [dl('WRI Aqueduct Geodata, GEMS/Water Quality, Flood Hazard Maps, IPCC Projections', 'Multi-source integration + CWRI computation + scenario projection', 'Detailed water risk analytics, basin-level reports, ESRS E3/TNFD disclosures, CDP Water package')],
