    [dl('IEA LCOP benchmarks + CBAM regulation + worldsteel emissions data', '6-route LCOP model + CBAM calculator + H2 break-even engine + carbon sensitivity', 'Steel producers, offtakers, infrastructure investors, and policy teams evaluating decarbonisation pathways')],
