    [dl('GFANZ framework + IEA industrial data + CBI transition finance criteria', 'Sector readiness radar + 16 deals + capital stack + programme intelligence', 'Banks structuring transition bonds, industrial companies raising green finance, and investors in hard-to-abate sectors')],
