    [dl('UNDO/Eion EW data + Nature study + Stripe Frontier advance purchase terms', '20-project pipeline + mineral comparison + scale economics + co-benefit radar + MRV intelligence', 'EW project developers, agricultural companies, carbon buyers, and investors assessing CDR portfolio')],
