    [dl('Puro.earth + EBC standards + IRA §45Q statute + IEA BECCS data', 'IRR/NPV project finance engine + 22 projects + §45Q eligibility + permanence scatter', 'Biochar producers, BECCS developers, carbon buyers, and investors evaluating biomass CDR economics')],
